"""Simplified LangChain-inspired adapter for OpenCode.

This provides battle-tested tool parsing WITHOUT the full LangChain dependency tree.
Uses the parsing logic we already copied (json_fixer.py) plus OpenCode's format_translator.
"""

from typing import Dict, Any, List, Optional
import json
import re

from .tools import ToolManager
from .format_translator import FormatTranslator


class SimpleLangChainAdapter:
    """Simplified adapter providing LangChain-style tool handling without dependencies.

    Provides:
    1. Robust JSON parsing (using json_fixer)
    2. Multiple format support (using format_translator)
    3. Auto-generated OpenAI-style schemas
    """

    def __init__(self, tool_manager: ToolManager):
        """Initialize adapter with OpenCode's tool manager.

        Args:
            tool_manager: OpenCode's existing ToolManager instance
        """
        self.tool_manager = tool_manager
        self.translator = FormatTranslator()

    def get_tool_schemas_for_model(self) -> List[Dict]:
        """Get OpenAI-style function schemas for model prompting.

        Returns:
            List of OpenAI-style function schemas
        """
        # Use the existing tool schemas from OpenCode
        schemas = self.tool_manager.get_tool_schemas()

        # Convert to OpenAI function calling format
        openai_schemas = []
        for schema in schemas:
            if 'function' in schema:
                openai_schemas.append(schema['function'])

        return openai_schemas

    def parse_and_validate(self, model_output: str) -> Optional[Dict[str, Any]]:
        """Parse model output using multiple strategies.

        Tries in order:
        1. Direct JSON parsing
        2. LangChain-style JSON extraction (from json_fixer)
        3. OpenCode's format_translator (handles quirky formats)

        Args:
            model_output: Raw text output from the model

        Returns:
            Parsed tool call dict or None
        """
        # Strategy 1: Try direct JSON parsing
        result = self._try_direct_json(model_output)
        if result:
            return result

        # Strategy 2: Try LangChain-style partial JSON parsing
        result = self._try_partial_json(model_output)
        if result:
            return result

        # Strategy 3: Fall back to OpenCode's translator for quirky formats
        try:
            result = self.translator.translate_tool_call(model_output)
            if result:
                return result
        except Exception:
            pass

        return None

    def _try_direct_json(self, text: str) -> Optional[Dict[str, Any]]:
        """Try parsing as direct JSON.

        Args:
            text: Model output text

        Returns:
            Parsed tool call or None
        """
        try:
            parsed = json.loads(text.strip())
            if isinstance(parsed, dict):
                # Check if it's a tool call
                if 'name' in parsed or 'type' in parsed:
                    return self._normalize_tool_call(parsed)
            elif isinstance(parsed, list) and len(parsed) > 0:
                # Array of tool calls - return first one
                if isinstance(parsed[0], dict):
                    return self._normalize_tool_call(parsed[0])
        except:
            pass

        return None

    def _try_partial_json(self, text: str) -> Optional[Dict[str, Any]]:
        """Try parsing with LangChain's partial JSON parser.

        Args:
            text: Model output text

        Returns:
            Parsed tool call or None
        """
        try:
            from .json_fixer import smart_json_parse

            parsed = smart_json_parse(text)
            if parsed and isinstance(parsed, dict):
                if 'name' in parsed or 'type' in parsed:
                    return self._normalize_tool_call(parsed)
        except Exception:
            pass

        return None

    def _normalize_tool_call(self, parsed: Dict) -> Dict[str, Any]:
        """Normalize parsed tool call to OpenCode format.

        Args:
            parsed: Parsed dict from JSON

        Returns:
            Normalized tool call dict
        """
        return {
            'type': 'tool_call',
            'name': parsed.get('name', parsed.get('tool', parsed.get('function', ''))),
            'args': parsed.get('args', parsed.get('arguments', parsed.get('parameters', {})))
        }

    def list_tools(self) -> List[str]:
        """Get list of all available tool names.

        Returns:
            List of tool names
        """
        return self.tool_manager.get_all_tool_names()
